22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	};
29	
30	const itemPremium = (item: Item): number => {
31	  const base = BASE_PREMIUM[item.type];
32	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
33	  return base + firstInsuranceSurcharge;
34	};
35	
36	const quoteStep = (step: QuoteStep): QuoteResult => {
37	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
38	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
39	};
40	
41	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
42	  const results = scenario.steps.map(quoteStep);
43	  return { results };
44	};
